const clampInt = (value, min, max) => Math.max(min, Math.min(max, Math.round(value)));

const currentHcsr04 = Number(global.get("hcsr04_offset_cm"));
const currentDroplet = Number(global.get("droplet_offset_raw"));
const currentTurbidity = Number(global.get("turbidity_offset_raw"));
const currentTds = Number(global.get("tds_offset_raw"));
const currentDhtTemp = Number(global.get("dht11_temp_offset_c"));
const currentDhtHumidity = Number(global.get("dht11_humidity_offset_pct"));

const hcsr04Offset = clampInt(Number.isFinite(currentHcsr04) ? currentHcsr04 : 0, -5, 5);
const dropletOffset = clampInt(Number.isFinite(currentDroplet) ? currentDroplet : 0, -300, 300);
const turbidityOffset = clampInt(Number.isFinite(currentTurbidity) ? currentTurbidity : 0, -200, 200);
const tdsOffset = clampInt(Number.isFinite(currentTds) ? currentTds : 0, -300, 300);
const dht11TempOffset = clampInt(Number.isFinite(currentDhtTemp) ? currentDhtTemp : 0, -10, 10);
const dht11HumidityOffset = clampInt(Number.isFinite(currentDhtHumidity) ? currentDhtHumidity : 0, -20, 20);

global.set("hcsr04_offset_cm", hcsr04Offset);
global.set("droplet_offset_raw", dropletOffset);
global.set("turbidity_offset_raw", turbidityOffset);
global.set("tds_offset_raw", tdsOffset);
global.set("dht11_temp_offset_c", dht11TempOffset);
global.set("dht11_humidity_offset_pct", dht11HumidityOffset);

msg.payload = {
  hcsr04_offset_cm: hcsr04Offset,
  droplet_offset_raw: dropletOffset,
  turbidity_offset_raw: turbidityOffset,
  tds_offset_raw: tdsOffset,
  dht11_temp_offset_c: dht11TempOffset,
  dht11_humidity_offset_pct: dht11HumidityOffset
};
return msg;

const clampInt = (value, min, max) => Math.max(min, Math.min(max, Math.round(value)));

const key = String(msg.topic || "hcsr04_offset_cm");
const raw = Number(msg.payload);
if (!Number.isFinite(raw)) {
  return null;
}

if (key === "hcsr04_offset_cm") {
  global.set("hcsr04_offset_cm", clampInt(raw, -5, 5));
} else if (key === "droplet_offset_raw") {
  global.set("droplet_offset_raw", clampInt(raw, -300, 300));
} else if (key === "turbidity_offset_raw") {
  global.set("turbidity_offset_raw", clampInt(raw, -200, 200));
} else if (key === "tds_offset_raw") {
  global.set("tds_offset_raw", clampInt(raw, -300, 300));
} else if (key === "dht11_temp_offset_c") {
  global.set("dht11_temp_offset_c", clampInt(raw, -10, 10));
} else if (key === "dht11_humidity_offset_pct") {
  global.set("dht11_humidity_offset_pct", clampInt(raw, -20, 20));
} else {
  return null;
}

const currentHcsr04 = Number(global.get("hcsr04_offset_cm"));
const currentDroplet = Number(global.get("droplet_offset_raw"));
const currentTurbidity = Number(global.get("turbidity_offset_raw"));
const currentTds = Number(global.get("tds_offset_raw"));
const currentDhtTemp = Number(global.get("dht11_temp_offset_c"));
const currentDhtHumidity = Number(global.get("dht11_humidity_offset_pct"));

const hcsr04Offset = clampInt(Number.isFinite(currentHcsr04) ? currentHcsr04 : 0, -5, 5);
const dropletOffset = clampInt(Number.isFinite(currentDroplet) ? currentDroplet : 0, -300, 300);
const turbidityOffset = clampInt(Number.isFinite(currentTurbidity) ? currentTurbidity : 0, -200, 200);
const tdsOffset = clampInt(Number.isFinite(currentTds) ? currentTds : 0, -300, 300);
const dht11TempOffset = clampInt(Number.isFinite(currentDhtTemp) ? currentDhtTemp : 0, -10, 10);
const dht11HumidityOffset = clampInt(Number.isFinite(currentDhtHumidity) ? currentDhtHumidity : 0, -20, 20);

global.set("hcsr04_offset_cm", hcsr04Offset);
global.set("droplet_offset_raw", dropletOffset);
global.set("turbidity_offset_raw", turbidityOffset);
global.set("tds_offset_raw", tdsOffset);
global.set("dht11_temp_offset_c", dht11TempOffset);
global.set("dht11_humidity_offset_pct", dht11HumidityOffset);

msg.payload = {
  hcsr04_offset_cm: hcsr04Offset,
  droplet_offset_raw: dropletOffset,
  turbidity_offset_raw: turbidityOffset,
  tds_offset_raw: tdsOffset,
  dht11_temp_offset_c: dht11TempOffset,
  dht11_humidity_offset_pct: dht11HumidityOffset
};
return msg;

const p = msg.payload || {};
if (String(p.type || "") !== "sensor") {
  return null;
}

const clampInt = (value, min, max) => Math.max(min, Math.min(max, Math.round(value)));
const toPressedText = (value) => Number(value) === 1 ? "GEDRUECKT" : "frei";
const toOnOffText = (value) => Number(value) === 1 ? "ON" : "OFF";

let hcsr04Offset = Number(global.get("hcsr04_offset_cm"));
if (!Number.isFinite(hcsr04Offset)) {
  hcsr04Offset = 0;
}
hcsr04Offset = clampInt(hcsr04Offset, -5, 5);
p.hcsr04_offset_cm = hcsr04Offset;

let dropletOffset = Number(global.get("droplet_offset_raw"));
if (!Number.isFinite(dropletOffset)) {
  dropletOffset = 0;
}
dropletOffset = clampInt(dropletOffset, -300, 300);
p.droplet_offset_raw = dropletOffset;

let turbidityOffset = Number(global.get("turbidity_offset_raw"));
if (!Number.isFinite(turbidityOffset)) {
  turbidityOffset = 0;
}
turbidityOffset = clampInt(turbidityOffset, -200, 200);
p.turbidity_offset_raw = turbidityOffset;

let tdsOffset = Number(global.get("tds_offset_raw"));
if (!Number.isFinite(tdsOffset)) {
  tdsOffset = 0;
}
tdsOffset = clampInt(tdsOffset, -300, 300);
p.tds_offset_raw = tdsOffset;

let dht11TempOffset = Number(global.get("dht11_temp_offset_c"));
if (!Number.isFinite(dht11TempOffset)) {
  dht11TempOffset = 0;
}
dht11TempOffset = clampInt(dht11TempOffset, -10, 10);
p.dht11_temp_offset_c = dht11TempOffset;

let dht11HumidityOffset = Number(global.get("dht11_humidity_offset_pct"));
if (!Number.isFinite(dht11HumidityOffset)) {
  dht11HumidityOffset = 0;
}
dht11HumidityOffset = clampInt(dht11HumidityOffset, -20, 20);
p.dht11_humidity_offset_pct = dht11HumidityOffset;

const hcsr04Raw = Number(p.hcsr04_distance_cm);
const hcsr04Status = String(p.hcsr04_status || "missing");
if (hcsr04Status === "ok" && Number.isFinite(hcsr04Raw)) {
  p.hcsr04_distance_display_cm = hcsr04Raw + hcsr04Offset;
} else {
  p.hcsr04_distance_display_cm = p.hcsr04_distance_cm;
}

const dropletRaw = Number(p.droplet_raw);
const dropletStatus = String(p.droplet_status || "missing");
if (dropletStatus === "ok" && Number.isFinite(dropletRaw)) {
  p.droplet_display_raw = clampInt(dropletRaw + dropletOffset, 0, 1023);
} else {
  p.droplet_display_raw = p.droplet_raw;
}

const turbidityRaw = Number(p.turbidity_raw);
const turbidityStatus = String(p.turbidity_status || "missing");
if (turbidityStatus === "ok" && Number.isFinite(turbidityRaw)) {
  p.turbidity_display_raw = clampInt(turbidityRaw + turbidityOffset, 0, 1023);
} else {
  p.turbidity_display_raw = p.turbidity_raw;
}

const tdsRaw = Number(p.tds_raw);
const tdsStatus = String(p.tds_status || "missing");
if (tdsStatus === "ok" && Number.isFinite(tdsRaw)) {
  p.tds_display_raw = clampInt(tdsRaw + tdsOffset, 0, 1023);
} else {
  p.tds_display_raw = p.tds_raw;
}

const dht11TempRaw = Number(p.dht11_temp_c);
const dht11HumidityRaw = Number(p.dht11_humidity_pct);
const dht11Status = String(p.dht11_status || "missing");
if (dht11Status === "ok" && Number.isFinite(dht11TempRaw)) {
  p.dht11_temp_display_c = clampInt(dht11TempRaw + dht11TempOffset, -20, 80);
} else {
  p.dht11_temp_display_c = p.dht11_temp_c;
}
if (dht11Status === "ok" && Number.isFinite(dht11HumidityRaw)) {
  p.dht11_humidity_display_pct = clampInt(dht11HumidityRaw + dht11HumidityOffset, 0, 100);
} else {
  p.dht11_humidity_display_pct = p.dht11_humidity_pct;
}

p.btn_blue_pump_text = toPressedText(p.btn_blue_pump);
p.btn_yellow_stepper1_text = toPressedText(p.btn_yellow_stepper1);
p.btn_yellow_stepper2_text = toPressedText(p.btn_yellow_stepper2);
p.btn_red_stop_text = toPressedText(p.btn_red_stop);
p.btn_green_start_ack_text = toPressedText(p.btn_green_start_ack);

p.led_blue_pump_text = toOnOffText(p.led_blue_pump);
p.led_yellow_stepper1_text = toOnOffText(p.led_yellow_stepper1);
p.led_yellow_stepper2_text = toOnOffText(p.led_yellow_stepper2);
p.led_red_stop_text = toOnOffText(p.led_red_stop);
p.led_green_start_ack_text = toOnOffText(p.led_green_start_ack);

msg.payload = p;
return msg;

const RELAY_PINS = [22, 23, 24, 25];

const ensureRelayState = () => {
  const current = flow.get("relay_state") || {};
  const normalized = {};
  for (const pin of RELAY_PINS) {
    normalized[String(pin)] = Number(current[String(pin)]) === 1 ? 1 : 0;
  }
  flow.set("relay_state", normalized);
  return normalized;
};

const buildUiPayload = (state) => ({
  relay1_state_text: state["22"] ? "ON" : "OFF",
  relay2_state_text: state["23"] ? "ON" : "OFF",
  relay3_state_text: state["24"] ? "ON" : "OFF",
  relay4_state_text: state["25"] ? "ON" : "OFF"
});

const state = ensureRelayState();

if (String(msg.payload || "") === "INIT_OFFSET") {
  return [null, { payload: buildUiPayload(state) }];
}

if (String(msg.topic || "") === "relay_toggle") {
  const pin = Number(msg.payload);
  if (!RELAY_PINS.includes(pin)) {
    return null;
  }

  const key = String(pin);
  const nextState = state[key] === 1 ? 0 : 1;
  msg.payload = `ACT,${pin},${nextState}`;
  msg.topic = "";
  return [msg, null];
}

const p = msg.payload || {};
if (String(p.type || "") !== "act") {
  return null;
}

const pin = Number(p.pin);
if (!RELAY_PINS.includes(pin)) {
  return null;
}

if (Number(p.ok) === 1) {
  state[String(pin)] = Number(p.state) === 1 ? 1 : 0;
  flow.set("relay_state", state);
}

return [null, { payload: buildUiPayload(state) }];

if (String(msg.topic || "") !== "stepper_action") {
  return null;
}

const action = String(msg.payload || "");
if (action === "run_5s") {
  msg.payload = "STEPPER_5S";
} else if (action === "rotate_120") {
  msg.payload = "STEPPER_120";
} else if (action === "run_5s_m2") {
  msg.payload = "STEPPER2_5S";
} else if (action === "rotate_120_m2") {
  msg.payload = "STEPPER2_120";
} else {
  return null;
}

msg.topic = "";
return msg;

const LED_KEYS = ["1", "2", "3", "4", "5"];

const ensureLedState = () => {
  const current = flow.get("led_state") || {};
  const normalized = {};
  for (const key of LED_KEYS) {
    normalized[key] = Number(current[key]) === 1 ? 1 : 0;
  }
  flow.set("led_state", normalized);
  return normalized;
};

const buildUiPayload = (state) => ({
  led_blue_pump_text: state["1"] ? "ON" : "OFF",
  led_yellow_stepper1_text: state["2"] ? "ON" : "OFF",
  led_yellow_stepper2_text: state["3"] ? "ON" : "OFF",
  led_red_stop_text: state["4"] ? "ON" : "OFF",
  led_green_start_ack_text: state["5"] ? "ON" : "OFF"
});

const state = ensureLedState();

if (String(msg.payload || "") === "INIT_OFFSET") {
  return [null, { payload: buildUiPayload(state) }];
}

if (String(msg.topic || "") === "led_toggle") {
  const index = Number(msg.payload);
  if (!Number.isFinite(index) || index < 1 || index > 5) {
    return null;
  }

  const key = String(index);
  const nextState = state[key] === 1 ? 0 : 1;
  msg.payload = `LED,${index},${nextState}`;
  msg.topic = "";
  return [msg, null];
}

const p = msg.payload || {};
if (String(p.type || "") === "sensor") {
  const sensorMap = {
    "1": Number(p.led_blue_pump),
    "2": Number(p.led_yellow_stepper1),
    "3": Number(p.led_yellow_stepper2),
    "4": Number(p.led_red_stop),
    "5": Number(p.led_green_start_ack)
  };
  for (const key of LED_KEYS) {
    if (sensorMap[key] === 1 || sensorMap[key] === 0) {
      state[key] = sensorMap[key];
    }
  }
  flow.set("led_state", state);
  return [null, { payload: buildUiPayload(state) }];
}

if (String(p.type || "") !== "led") {
  return null;
}

const index = Number(p.index);
if (!Number.isFinite(index) || index < 1 || index > 5) {
  return null;
}
if (Number(p.ok) === 1) {
  state[String(index)] = Number(p.state) === 1 ? 1 : 0;
  flow.set("led_state", state);
}

return [null, { payload: buildUiPayload(state) }];
